<?php namespace App\Models; use Illuminate\Database\Eloquent\Factories\HasFactory; use Illuminate\Database\Eloquent\Model; use Illuminate\Database\Eloquent\Relations\BelongsTo; class Housing extends Model { use HasFactory; protected $fillable = [ 'company_id', 'site_id', 'name', 'address', 'capacity', 'status', 'payload', ]; protected function casts(): array { return [ 'capacity' => 'integer', 'payload' => 'array', ]; } public function company(): BelongsTo { return $this->belongsTo(Company::class); } public function site(): BelongsTo { return $this->belongsTo(Site::class); } }
